I'm not using any of these (two) approaches defined here. Maybe it's also possible to do something
with c++-coroutines(?)... However, I'm currently using an abstract Promise class. 
This has the advantage, that I don't need to start a new thread with std::async or std::thread inside the pybind11-definition:
```cpp
template<typename T>
    class Promise
    {
    public:
        class Implementation
        {
        public:
            virtual ~Implementation() = default;
            virtual void set_value(T) = 0;
            virtual void set_exception(std::exception_ptr) = 0;
        };

        Promise(std::shared_ptr<Implementation> implementation)
            : _implementation(std::move(implementation))
        {
        }

        void set_value(T t)
        {
            _implementation->set_value(std::move(t));
        }

        void set_exception(std::exception_ptr e)
        {
            _implementation->set_exception(std::move(e));
        }

    private:
        std::shared_ptr<Implementation> _implementation;
    };

... later ... :
    
    void Foo::get_bar(Promise<int>&&) const;

```

Another approach was to define a "TaskQueue" (a threaded event-loop), where "Driven" means, that
the object is assigned to such a "TaskQueue":
```cpp
 template<typename Driven, typename Param>
    auto async(py::module& asyncio, void(Driven::* member)(Param))
    {
        return [=](Driven& object, Param param) mutable
        {
            auto promise = std::make_shared<Promise<void>>(asyncio);
            auto future = promise->get_future();
            object.task_queue()->run([object = &object, member, promise{ std::move(promise) }, param{std::move(param)}]() mutable {
                try
                {
                    (*object.*member)(std::move(param));
                    promise->set_value();
                }
                catch (...)
                {
                    promise->set_exception(std::current_exception());
                }
            });
            return future;
        };
    }
```
